interface CommentAnnotationDataProvider {
  get?: (request: CommentAnnotationGetRequest) => Promise<ResolverResponse<CommentAnnotation>>;
  save?: (request: CommentAnnotationSaveRequest) => Promise<ResolverResponse<void>>;
  delete?: (request: CommentAnnotationDeleteRequest) => Promise<ResolverResponse<void>>;
  config?: ResolverConfig;
}

interface ResolverConfig {
  getConfig?: { url: string };
  saveConfig?: { url: string };
  deleteConfig?: { url: string };
  additionalFields?: string[];
}

